// Ktor client used in commonMain
import io.ktor.client.HttpClient
import io.ktor.client.call.body
import io.ktor.client.plugins.contentnegotiation.ContentNegotiation
import io.ktor.client.request.get
import io.ktor.serialization.kotlinx.json.json
import kotlinx.serialization.Serializable

@Serializable data class User(val id: Long, val name: String)

class UserApi(private val client: HttpClient) {
  suspend fun fetch(id: Long): User = client.get("https://api/users/\$id").body()
}

fun makeClient(): HttpClient = HttpClient {
  install(ContentNegotiation) { json() }
}

// commonMain — shared VM
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

data class CounterUi(val count: Int = 0)

class CounterViewModel(private val repo: CounterRepo) : ViewModel() {
  private val _state = MutableStateFlow(CounterUi())
  val state: StateFlow<CounterUi> = _state.asStateFlow()

  fun increment() = viewModelScope.launch {
    val next = repo.increment()
    _state.value = CounterUi(count = next)
  }
}

// Android — Compose binds directly
@Composable
fun CounterScreen(vm: CounterViewModel = viewModel()) {
  val state by vm.state.collectAsStateWithLifecycle()
  Button(onClick = vm::increment) { Text("\${state.count}") }
}

