// Decision checklist (in code form)
fun shouldUseKMP(
  isLongLivedProduct: Boolean,
  bothPlatformsActive: Boolean,
  businessLogicShareIsHigh: Boolean,
  teamHasKotlinAndIosSkills: Boolean,
  willingToInvestInTooling: Boolean
): Boolean = listOf(
  isLongLivedProduct,
  bothPlatformsActive,
  businessLogicShareIsHigh,
  teamHasKotlinAndIosSkills,
  willingToInvestInTooling
).count { it } >= 4

// Adoption strategy
// 1. Start with the smallest non-trivial module: domain models + a network client.
// 2. Wrap it in platform DI so iOS/Android consume an interface, not the KMP framework directly.
// 3. Verify hot reload + crash reporting + tests work end-to-end on both platforms.
// 4. Expand: persistence, then shared ViewModels, then maybe Compose Multiplatform UI for selected screens.
// 5. Don't migrate UI just because you can — measure the win first.
